import{_ as t,G as r,c as s,o as i,j as a,J as o,a6 as n,a as d}from"./chunks/framework.D3uGTwuV.js";const g=JSON.parse('{"title":"node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件”","description":"","frontmatter":{},"headers":[],"relativePath":"技巧/node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件“.md","filePath":"技巧/node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件“.md","lastUpdated":1775109753000}'),p={name:"技巧/node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件“.md"};function h(c,e,_,m,k,b){const l=r("ArticleMetadata");return i(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[e[0]||(e[0]=a("h1",{id:"node-js-在-powershell-上运行-npm-会询问-你要如何打开这个文件",tabindex:"-1"},[d("node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件” "),a("a",{class:"header-anchor",href:"#node-js-在-powershell-上运行-npm-会询问-你要如何打开这个文件","aria-label":"Permalink to “node.js - 在 PowerShell 上运行 npm 会询问 “你要如何打开这个文件””"},"​")],-1)),o(l),e[1]||(e[1]=n('<h2 id="奇遇" tabindex="-1">奇遇 <a class="header-anchor" href="#奇遇" aria-label="Permalink to “奇遇”">​</a></h2><p>今天准备打开 VSCode 玩一会 vue， 使用 <code>npm run serve</code> 命令后直接给我干个打开文件窗口，给我整的一头雾水。。。。。</p><h2 id="试错" tabindex="-1">试错 <a class="header-anchor" href="#试错" aria-label="Permalink to “试错”">​</a></h2><p>接下来我踏上解决这个错误的路程，以下是我心路历程：</p><ol><li>检查环境变量，重新复制粘贴 node 路径，没错啊。</li><li>重新安装 npm 也没问题啊。</li><li>在 PowerShell 里使用命令查看 node、vue 版本，都可以正常显示，头大。</li><li>郁闷了，那就重新安装 nodejs 吧，安装包版改为了压缩包版，还不行！！！</li><li>什么破电脑，刚买来还没过 7 天无理由，难不成就要让我重装系统？？？黑人问号？？？</li></ol><h2 id="偶然" tabindex="-1">偶然 <a class="header-anchor" href="#偶然" aria-label="Permalink to “偶然”">​</a></h2><p>百度了半天也没找到结果，果断打开了谷歌，皇天不负有心人，还真让我给找到了！！！</p><h2 id="踏破铁鞋无觅处" tabindex="-1">踏破铁鞋无觅处 <a class="header-anchor" href="#踏破铁鞋无觅处" aria-label="Permalink to “踏破铁鞋无觅处”">​</a></h2><p>以下为解决方法：</p><ol><li>在 powershell 中运行命令 <code>get-command npm</code></li></ol><div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">command npm</span></span></code></pre></div><ol start="2"><li>它可能会给你错误的路径，蓝色标线所示。</li></ol><p><img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1753262367430-8b238646-52ca-4f67-b4a4-918efae56374.png" alt=""></p><ol start="3"><li>打开 Source 显示路径，找到 npm 这个文件，删除掉</li></ol><p><img src="https://cdn.nlark.com/yuque/0/2025/png/42939896/1753262393044-5c5b4872-f8db-4b86-a44a-d4623f1caa23.png" alt=""></p><ol start="4"><li>ok 可以啦，重新在 PowerShell 里输入命令 <code>npm -v</code>，终于正常显示版本号了。</li></ol><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>你若问我为什么 systsem32 文件夹下，会有个 npm 文件，当然啦，我也不知道，难道中了毒？</p><p>最后附上原文链接<a href="https://www.coder.work/article/559669" target="_blank" rel="noreferrer">https://www.coder.work/article/559669</a></p>',19))])}const w=t(p,[["render",h]]);export{g as __pageData,w as default};
